#include <stdio.h>
#include <stdint.h>

const long long MOD = 1000000007LL;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long sum = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            sum = (sum + x) % MOD;
        }
        if (sum < 0) sum += MOD;
        int Q; scanf("%d", &Q);
        for (int i = 0; i < Q; ++i) {
            long long dummy; scanf("%lld", &dummy); // rotation amount, ignored
            sum = (sum * 2) % MOD;
            printf("%lld\n", sum);
        }
    }
    return 0;
}

