#!/usr/bin/env python3
import sys
MOD = 1000000007

def main():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        s = 0
        for _ in range(N):
            s = (s + next(it)) % MOD
        if s < 0:
            s += MOD
        Q = next(it)
        for _ in range(Q):
            _ = next(it)  # rotation amount, ignored
            s = (s * 2) % MOD
            out_lines.append(str(s))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

